import{_ as n,c as i,o as t,a1 as l}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Anhang: Referenzmaterialien | opencode-agent-skills","description":"Lernen Sie die Anhangsinhalte von opencode-agent-skills kennen, einschließlich Best Practices für die Skill-Entwicklung und API-Tool-Referenz. Beherrschen Sie Techniken und Richtlinien zum Schreiben hochwertiger Skills.","frontmatter":{"title":"Anhang: Referenzmaterialien | opencode-agent-skills","sidebarTitle":"Skill-Entwicklungsreferenz","subtitle":"Anhang: Referenzmaterialien und Entwicklungsrichtlinien","description":"Lernen Sie die Anhangsinhalte von opencode-agent-skills kennen, einschließlich Best Practices für die Skill-Entwicklung und API-Tool-Referenz. Beherrschen Sie Techniken und Richtlinien zum Schreiben hochwertiger Skills.","order":5},"headers":[],"relativePath":"de/joshuadavidthomas/opencode-agent-skills/appendix/index.md","filePath":"de/joshuadavidthomas/opencode-agent-skills/appendix/index.md"}'),r={name:"de/joshuadavidthomas/opencode-agent-skills/appendix/index.md"};function a(s,e,h,c,o,d){return t(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="anhang" tabindex="-1">Anhang <a class="header-anchor" href="#anhang" aria-label="Permalink to &quot;Anhang&quot;">​</a></h1><p>Dieses Kapitel bietet Referenzmaterialien und Entwicklungsrichtlinien für OpenCode Agent Skills, um Ihnen beim Schreiben hochwertiger Skills zu helfen und einen schnellen Zugriff auf API-Schnittstellen zu ermöglichen.</p><h2 id="inhalt-dieses-kapitels" tabindex="-1">Inhalt dieses Kapitels <a class="header-anchor" href="#inhalt-dieses-kapitels" aria-label="Permalink to &quot;Inhalt dieses Kapitels&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Seite</th><th>Beschreibung</th></tr></thead><tbody><tr><td><a href="./best-practices/">Best Practices für die Skill-Entwicklung</a></td><td>Beherrschen Sie Techniken und Richtlinien zum Schreiben hochwertiger Skills, einschließlich Namenskonventionen, Beschreibungserstellung, Verzeichnisorganisation, Skriptverwendung und mehr</td></tr><tr><td><a href="./api-reference/">API-Tool-Referenz</a></td><td>Sehen Sie detaillierte Parameter und Rückgabewerte aller verfügbaren Tools, einschließlich <code>get_available_skills</code>, <code>read_skill_file</code>, <code>run_skill_script</code>, <code>use_skill</code></td></tr></tbody></table><h2 id="empfohlener-lernpfad" tabindex="-1">Empfohlener Lernpfad <a class="header-anchor" href="#empfohlener-lernpfad" aria-label="Permalink to &quot;Empfohlener Lernpfad&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Empfohlene Reihenfolge</p><ol><li><strong>Zuerst Best Practices lernen</strong> → Verstehen Sie Richtlinien und Techniken für die Skill-Entwicklung, um häufige Fehler zu vermeiden</li><li><strong>Dann API-Referenz konsultieren</strong> → Schlagen Sie bei Problemen in der tatsächlichen Entwicklung spezifische Parameter und Rückgabewerte nach</li></ol></div><p>Diese beiden Inhalte haben unterschiedliche Positionierungen:</p><ul><li><strong>Best Practices</strong>: Geeignet zum Durchlesen vor dem Schreiben von Skills, um korrekte Entwicklungsgewohnheiten zu etablieren</li><li><strong>API-Referenz</strong>: Geeignet als Nachschlagewerk, um bei Bedarf spezifische Details nachzuschlagen</li></ul><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Empfohlen, zuerst abzuschließen</p><p>Bevor Sie dieses Kapitel lesen, wird empfohlen, dass Sie bereits:</p><ul><li><a href="./../start/creating-your-first-skill/">Erstellen Sie Ihren ersten Skill</a> abgeschlossen haben, um die grundlegende Skill-Struktur zu verstehen</li><li>Den <a href="./../platforms/skill-discovery-mechanism/">Skill-Erkennungsmechanismus</a> verstehen, um zu begreifen, wie das Plugin Skills findet</li></ul></div><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss dieses Kapitels können Sie:</p><ul><li>Die <a href="./../faq/troubleshooting/">Fehlerbehebung</a> ansehen, um Probleme bei der Verwendung zu lösen</li><li>Die <a href="./../faq/security-considerations/">Sicherheitshinweise</a> verstehen, um die Sicherheit der Skills zu gewährleisten</li><li>Die <a href="./../changelog/">Versionshistorie</a> überprüfen, um die Entwicklung und neuen Funktionen des Plugins zu verstehen</li></ul>',13)])])}const k=n(r,[["render",a]]);export{g as __pageData,k as default};
